<template>
  <div class="factory-cabinet">
    <button
        class="logout-btn"
        @click="logout"
        :style="{ opacity: logoutBtnOpacity, transition: 'opacity 0.3s' }"
    >
      Выйти
    </button>
    <div class="cabinet-header">
      <span class="cabinet-header-icon">
        <img src="https://img.icons8.com/color/48/000000/factory.png" alt="icon" />
      </span>
      <div>
        <h2>Личный кабинет производителя</h2>
        <p>Здесь вы можете управлять информацией о вашей компании и размещать новые товары для продажи.</p>
      </div>
    </div>
    <div class="cabinet-main">
      <div class="cabinet-left">
        <div class="manufacturer-card">
          <h3>{{ manufacturer.name }}</h3>
          <p><b>Страна:</b> {{ manufacturer.country }}</p>
          <p><b>Специализация:</b> {{ manufacturer.specialty }}</p>
          <p><b>Год основания:</b> {{ manufacturer.founded }}</p>
          <p class="manuf-desc">{{ manufacturer.desc }}</p>
        </div>
      </div>
      <div class="cabinet-right">
        <div class="add-products-row">
          <div class="add-product-block">
            <h4>Добавить товар</h4>
            <form @submit.prevent="addProduct">
              <input v-model="newProduct.name" placeholder="Название товара" required />
              <input v-model="newProduct.image" placeholder="Ссылка на изображение" required />
              <textarea v-model="newProduct.desc" placeholder="Описание товара" required></textarea>
              <button type="submit">Добавить</button>
            </form>
          </div>
          <div class="added-products-block">
            <h5>Добавленные товары:</h5>
            <div v-if="products.length">
              <div v-for="(product, idx) in products" :key="idx" class="product-item">
                <img :src="product.image" :alt="product.name" />
                <div>
                  <b>{{ product.name }}</b>
                  <div>{{ product.desc }}</div>
                </div>
              </div>
            </div>
            <div v-else class="no-products">
              <span style="font-size:2rem;">🛒</span>
              <div>Пока нет добавленных товаров.<br>Добавьте первый товар!</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

const manufacturers = [
  {
    name: 'ООО "ТехДеталь"',
    country: 'Россия',
    specialty: 'Композитные лопасти для БПЛА',
    founded: 2012,
    desc: 'Ведущий производитель композитных деталей для беспилотных летательных аппаратов. Поставляет продукцию для крупных авиастроительных компаний.'
  },
  {
    name: 'SkyParts Ltd.',
    country: 'Германия',
    specialty: 'Электроника и автопилоты',
    founded: 2008,
    desc: 'Разработка и производство современных автопилотов и систем управления для дронов и вертолётов.'
  },
  {
    name: 'AeroPlast',
    country: 'Китай',
    specialty: 'Корпуса и шасси',
    founded: 2015,
    desc: 'Известен качественными и лёгкими корпусами для БПЛА, а также инновационными решениями в области шасси.'
  }
]

export default {
  name: 'FactoryCabinet',
  data() {
    return {
      manufacturer: manufacturers[Math.floor(Math.random() * manufacturers.length)],
      newProduct: { name: '', image: '', desc: '' },
      products: [],
      logoutBtnOpacity: 1 // ← добавили сюда
    }
  },
  created() {
    if (localStorage.getItem('isFactoryLoggedIn') !== 'true') {
      this.$router.push('/for-manufacturers')
    }
  },
  mounted() {
    window.addEventListener('scroll', this.handleScroll);
  },
  beforeUnmount() {
    window.removeEventListener('scroll', this.handleScroll);
  },
  methods: {
    logout() {
      localStorage.removeItem('isFactoryLoggedIn')
      this.$router.push('/for-manufacturers')
    },
    addProduct() {
      this.products.push({ ...this.newProduct })
      this.newProduct = { name: '', image: '', desc: '' }
    },
    handleScroll() {
      if (window.innerWidth <= 600) {
        const currentScroll = window.scrollY;
        this.logoutBtnOpacity = Math.max(1 - currentScroll / 120, 0.2);
      } else {
        this.logoutBtnOpacity = 1;
      }
    }
  }
}

</script>

