<template>
  <section class="uav-hero">
    <div class="uav-controls">
      <div class="uav-search-wrap">
        <span class="uav-search-icon">🔍</span>
        <input
            v-model="search"
            class="uav-search"
            type="text"
            placeholder="Поиск дрона..."
        />
      </div>
      <div class="uav-categories-btns">
        <button
            v-for="cat in categories"
            :key="cat"
            :class="['uav-category-horizontal', { active: selectedCategory === cat }]"
            @click="selectCategory(cat)"
        >
          {{ cat }}
        </button>
      </div>
      <div class="uav-sort">
        <span class="uav-sort-icon">↕️</span>
        <select id="sort" v-model="sortOrder">
          <option value="default">По умолчанию</option>
          <option value="asc">Дешёвые</option>
          <option value="desc">Дорогие</option>
        </select>
      </div>
    </div>
    <div class="uav-list">
      <div
          v-for="uav in visibleUavs"
          :key="uav.id"
          class="uav-card"
      >
        <img :src="uav.image" :alt="uav.name" class="uav-img" />
        <h2 class="uav-name">{{ uav.name }}</h2>
        <p class="uav-desc">{{ uav.desc }}</p>
        <div class="uav-price">Цена: <span>{{ uav.price.toLocaleString() }} ₽</span></div>
        <div class="uav-card-actions">
          <button class="uav-btn add" @click="addToCart(uav)">В корзину</button>
          <router-link :to="`/uav/${uav.id}`" class="uav-btn details">Подробнее</router-link>
        </div>
      </div>
    </div>
    <transition name="fade">
      <div v-if="showToast" class="uav-toast">
        Товар добавлен в корзину!
      </div>
    </transition>
  </section>
</template>

