import { ref, computed, onMounted, onBeforeUnmount } from 'vue'

const categories = ['Все', 'Квадрокоптеры', 'Самолёты', 'Вертолёты']
const uavs = ref([
  { id: 1, name: 'DJI Mavic 3', desc: 'Компактный и мощный дрон для аэрофотосъёмки.', image: 'https://gisdata.ru/image/cachewebp/catalog/products/DJIMavic3_1-1000x1000.webp', category: 'Квадрокоптеры', price: 185000 },
  { id: 2, name: 'Parrot Anafi', desc: 'Лёгкий складной дрон с отличной камерой.', image: 'https://i.computer-bild.de/imgs/1/2/9/3/4/4/5/3/2a0db729229698be.jpg', category: 'Квадрокоптеры', price: 65000 },
  { id: 3, name: 'Autel EVO II', desc: 'Профессиональный дрон с 8K-камерой.', image: 'https://uralelectronica.ru/upload/iblock/080/xrxgmfddm8c79j3ph4p9tzjodeuplbso.png', category: 'Квадрокоптеры', price: 120000 },
  { id: 4, name: 'DJI Mini 2', desc: 'Ультралёгкий дрон для путешествий.', image: 'https://avatars.mds.yandex.net/get-goods_pic/10767871/hatc1776ae28d09b254c7441e55e340ca0f/600x600', category: 'Квадрокоптеры', price: 48000 },
  { id: 5, name: 'Hubsan Zino Pro', desc: 'Дрон с дальним радиусом и 4K-камерой.', image: 'https://avatars.mds.yandex.net/get-goods_pic/11021390/hatf8e37caf0e5d2f044d7cc2879073685f/600x600', category: 'Квадрокоптеры', price: 42000 },
  { id: 6, name: 'Skywalker X8', desc: 'Популярный БПЛА-самолёт для аэрофотосъёмки.', image: 'https://avatars.mds.yandex.net/i?id=6efe6d49e2f8eb5d85545521d111aa53_l-5235138-images-thumbs&n=13', category: 'Самолёты', price: 90000 },
  { id: 7, name: 'E-flite Timber X', desc: 'Манёвренный самолёт для FPV.', image: 'https://images.amainhobbies.com/images/large/efl/efl13875_2.jpg', category: 'Самолёты', price: 67000 },
  { id: 8, name: 'Volantex Ranger', desc: 'Самолёт-дрон для длительных полётов.', image: 'https://www.hobbyrc.co.uk/images/thumbs/0012616_volantexrc-ranger-2000mm-fpv-plane-pnp.jpeg', category: 'Самолёты', price: 54000 },
  { id: 9, name: 'X-UAV Talon', desc: 'БПЛА для мониторинга и картографии.', image: 'https://avatars.mds.yandex.net/i?id=5d5723e18ddc4a603e2cd63ef644516e_l-5297106-images-thumbs&n=13', category: 'Самолёты', price: 75000 },
  { id: 10, name: 'Zeta Sky Surfer', desc: 'Лёгкий и надёжный самолёт для FPV.', image: 'https://dizelop.ru/1/upload_Модель-самолета-с-дистанционным-wp-upload/32593.jpg', category: 'Самолёты', price: 32000 },
  { id: 11, name: 'Align T-Rex 700', desc: 'Профессиональный вертолёт для аэрофотосъёмки.', image: 'https://images.amain.com/images/large/agn/agnrh70e35a.jpg', category: 'Вертолёты', price: 210000 },
  { id: 12, name: 'Blade 230 S', desc: 'Манёвренный вертолёт для FPV.', image: 'https://www.bladehelis.com/dw/image/v2/BFBR_PRD/on/demandware.static/-/Sites-horizon-master/default/dw54547d71/Images/BLH/BLH1250_A1_NWVNWQI5.jpg', category: 'Вертолёты', price: 39000 },
  { id: 13, name: 'Syma S107G', desc: 'Компактный вертолёт для начинающих.', image: 'https://avatars.mds.yandex.net/get-mpic/10933212/2a0000018a842d24a8258307299bbf3325f5/orig', category: 'Вертолёты', price: 3500 },
  { id: 14, name: 'Walkera V450D03', desc: 'Вертолёт с 6-осевым гироскопом.', image: 'https://tehno-teca.ru/img/543/542453/walkera_v450d03_1.jpg', category: 'Вертолёты', price: 52000 },
  { id: 15, name: 'Esky 150X', desc: 'Мини-вертолёт для дома и улицы.', image: 'https://m.media-amazon.com/images/I/41QD9tgk8cL._AC_UF894,1000_QL80_.jpg', category: 'Вертолёты', price: 8000 },
  { id: 16, name: 'DJI Air 2S', desc: 'Дрон с 1-дюймовой камерой.', image: 'https://technolider.com/upload/iblock/4b2/qzvf1vqnfkc8p02jael8ghlhy0iaw40w/0.jpeg', category: 'Квадрокоптеры', price: 99000 },
  { id: 17, name: 'Parrot Bebop 2', desc: 'Компактный FPV-дрон.', image: 'https://static.abc.ru/unsafe/1040x0/abc.ru/upload/catalog/qp/c-/1540221177.1082qpc-lbd3k9-z1eex3waf5crwfhry0w-5j7mj.jpg', category: 'Квадрокоптеры', price: 37000 },
  { id: 18, name: 'Skywalker EVE-2000', desc: 'Дрон-самолёт для дальних миссий.', image: 'https://avatars.mds.yandex.net/i?id=e051d61b2d142f9a8e65bc432d3e5909_l-12246204-images-thumbs&n=13', category: 'Самолёты', price: 110000 },
  { id: 19, name: 'Blade 330 S', desc: 'Вертолёт для продвинутых пилотов.', image: 'https://i.ebayimg.com/images/g/IKgAAOSws3phzV6x/s-l640.jpg', category: 'Вертолёты', price: 45000 },
  { id: 20, name: 'X-UAV Mini Talon', desc: 'Компактный БПЛА-самолёт.', image: 'https://www.itsqv.com/QVM/images/c/c6/MT001a.jpg', category: 'Самолёты', price: 60000 }
])

const search = ref('')
const selectedCategory = ref('Все')
const showToast = ref(false)
const itemsPerPage = 8
const page = ref(1)
const sortOrder = ref('default')

const filteredUavs = computed(() => {
  let result = uavs.value
  if (selectedCategory.value && selectedCategory.value !== 'Все') {
    result = result.filter(uav => uav.category === selectedCategory.value)
  }
  if (search.value.trim()) {
    const q = search.value.trim().toLowerCase()
    result = result.filter(uav => uav.name.toLowerCase().includes(q))
  }
  if (sortOrder.value === 'asc') {
    result = [...result].sort((a, b) => a.price - b.price)
  } else if (sortOrder.value === 'desc') {
    result = [...result].sort((a, b) => b.price - a.price)
  }
  return result
})

const visibleUavs = computed(() => {
  return filteredUavs.value.slice(0, page.value * itemsPerPage)
})

function selectCategory(cat) {
  selectedCategory.value = cat
  page.value = 1
}

function addToCart(uav) {
  let cart = JSON.parse(localStorage.getItem('cart') || '[]')
  cart.push(uav)
  localStorage.setItem('cart', JSON.stringify(cart))
  showToast.value = true
  setTimeout(() => (showToast.value = false), 1500)
}

function handleScroll() {
  const bottom = window.innerHeight + window.scrollY >= document.body.offsetHeight - 100
  if (bottom && visibleUavs.value.length < filteredUavs.value.length) {
    page.value++
  }
}

onMounted(() => {
  window.addEventListener('scroll', handleScroll)
})
onBeforeUnmount(() => {
  window.removeEventListener('scroll', handleScroll)
})
</script>

